mapper.select:
SELECT ic.*, d.drug_name, u1.real_name as checker_name, u2.real_name as auditor_name FROM inventory_check ic LEFT JOIN drug_info d ON ic.drug_id = d.drug_id LEFT JOIN sys_user u1 ON ic.checker_id = u1.user_id LEFT JOIN sys_user u2 ON ic.auditor_id = u2.user_id
AND d.drug_name LIKE CONCAT('%', #{drugName}, '%')
AND ic.audit_status = #{auditStatus}
AND ic.check_date >= #{startDate}
AND ic.check_date <= #{endDate}
ORDER BY ic.create_time DESC
